		// Since we iterate i from 0 upwards, we check all possible i.

		if s[i] == s[j] {
			// We found the smallest such index i.
			return int64(i)
		}

		// Optimization: If i passes the middle, we have checked all unique pairs
		// and the middle element itself (if n is odd).
		// If we reach here and i >= j, we can stop because any further i will be larger
		// than the current i, and the relationship s[i] == s[n-i-1] would have been checked
		// when the smaller index (j) was used as the iteration variable earlier, unless i=j.
		// Since we check i up to n-1, let's stick to the simple loop condition or stop earlier.
		// The required index i must satisfy 0 <= i < n.
		// If we stop when i >= j, we cover all necessary checks:
		if i >= j {
			// If i >= j, we have checked all unique pairs (i, j) and the single middle element (if n is odd).
			// For i > j, the pair (j, i) was already checked when the loop variable was j.
			// For i = j (middle element), it was checked.
			break
		}
	}

	// If no such index is found after checking all relevant i.
	return -1
}
