func solve(s string) int64 {
	n := len(s)
	// We are looking for the smallest index i such that s[i] == s[n - 1 - i].
	// We only need to check up to the midpoint of the string, i.e., where i <= n - 1 - i.
	// This simplifies to 2*i <= n - 1, or i <= (n - 1) / 2 (integer division).
	maxI := (n - 1) / 2

	for i := 0; i <= maxI; i++ {
		j := n - 1 - i
		if s[i] == s[j] {
			// Since we iterate upwards starting from 0, the first match found is the smallest i.
			return int64(i)
		}
	}

	// If no such index is found
	return -1
}

